mapper.delete:
delete from payment_channel_contract_capability
where contract_id = #{contractId}
  and tenant_id = #{tenantId}

delete from payment_channel_contract_capability
where id = #{id}
  and tenant_id = #{tenantId}

mapper.select:
select count(1)
  from payment_method_route_rule_item rri
 where rri.tenant_id = #{tenantId}
   and rri.status = 1
   and rri.del_flag = 0
   and rri.contract_capability_id = #{contractCapabilityId}

select count(1)
from payment_method_route_rule rr
where rr.tenant_id = #{tenantId}
  and rr.status = 1
  and (rr.app_id is null or rr.app_id = #{applicationId})
  and (rr.subject_id is null or rr.subject_id = #{subjectId})
  and rr.method_code = #{methodCode}
  and rr.terminal_type = #{terminalType}
  and rr.fallback_enabled = 0
  and rr.del_flag = 0
